-- ============================================
-- 创建 prompts 表并导入默认提示词数据
-- ============================================

-- 如果类型已存在则删除（注意：会级联删除依赖该类型的列）
DROP TYPE IF EXISTS prompt_category CASCADE;

-- 重新创建类型
CREATE TYPE prompt_category AS ENUM ('writing', 'coding', 'design', 'analysis', 'other');

-- 如果表已存在则删除
DROP TABLE IF EXISTS public.prompts;

-- 创建表
CREATE TABLE public.prompts (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL UNIQUE,
  category prompt_category NOT NULL,
  description TEXT NOT NULL,
  content TEXT NOT NULL,
  tags TEXT[] DEFAULT '{}',
  created_at TIMESTAMP DEFAULT NOW()
);

ALTER TABLE public.prompts ENABLE ROW LEVEL SECURITY;

CREATE POLICY "所有人可查看提示词" ON public.prompts FOR SELECT USING (true);
CREATE POLICY "认证用户可添加提示词" ON public.prompts FOR INSERT WITH CHECK (auth.uid() IS NOT NULL);
CREATE POLICY "认证用户可更新提示词" ON public.prompts FOR UPDATE USING (auth.uid() IS NOT NULL);
CREATE POLICY "认证用户可删除提示词" ON public.prompts FOR DELETE USING (auth.uid() IS NOT NULL);

CREATE INDEX idx_prompts_category ON public.prompts(category);

-- 插入默认提示词数据
INSERT INTO public.prompts (title, category, description, content, tags) VALUES
-- 电商图片类
('电商产品主图设计', 'design', '生成高质量的电商产品展示图提示词', '请作为电商视觉设计专家，为以下产品创作主图设计方案：\n\n产品信息：\n- 产品名称：[填写产品名]\n- 产品类别：[填写类别]\n- 目标人群：[填写目标用户]\n- 品牌调性：[高端/简约/活泼/专业]\n\n设计要求：\n1. 构图：采用[居中/三分法/对角线]构图，产品占比画面60-70%\n2. 背景：[纯色渐变/场景化/透明底]，色调与产品形成对比但和谐\n3. 光影：[柔光箱照明/自然光/戏剧性侧光]，突出产品质感\n4. 角度：[45度俯拍/平视/仰拍]，展示产品最佳特征\n5. 道具：[相关配件/植物/几何体]，增强场景感但不喧宾夺主\n\n输出格式：\n- 提供3种不同风格方案（简约白底、场景化、创意合成）\n- 每种方案包含：构图描述、色彩搭配、光影设置、后期处理建议\n- 给出可直接使用的Midjourney/Stable Diffusion提示词', ARRAY['电商', '产品图', '主图', '设计']),

('AI模特换装生成', 'design', '为服装电商生成AI模特试穿图', '作为AI时尚摄影师，请生成服装模特展示图：\n\n服装信息：\n- 品类：[上衣/裤子/裙子/外套/套装]\n- 风格：[休闲/商务/运动/复古/潮流]\n- 颜色：[主色调]\n- 材质：[棉麻/丝绸/牛仔/皮革/混纺]\n\n模特设定：\n- 人种：[亚洲/欧美/拉丁/非洲]\n- 年龄：[18-25/25-35/35-45岁]\n- 体型：[纤细/标准/丰满/健身]\n- 表情：[自然微笑/自信/酷飒/温柔]\n\n拍摄场景：\n- 背景：[纯色背景/街拍场景/室内棚拍/自然风光]\n- 姿势：[站姿全身/坐姿/行走动态/特写半身]\n- 光线：[柔和自然光/金色时刻/影棚灯光/阴天漫射]\n\n技术要求：\n- 分辨率：不低于2K\n- 面部细节：清晰自然，无明显AI痕迹\n- 服装贴合：褶皱自然，版型准确\n- 手部处理：避免出现畸形手指\n\n输出3张不同角度/姿势的效果图描述', ARRAY['电商', '服装', 'AI模特', '换装']),

('商品详情页视觉策划', 'design', '策划完整的电商详情页视觉方案', '请作为电商视觉策划师，为以下产品制定详情页视觉方案：\n\n产品：[产品名称]\n卖点：[核心卖点1、2、3]\n竞品差异化：[与竞品相比的独特之处]\n\n页面结构规划：\n1. 首屏海报（1920x600）\n   - 主题：一句话核心卖点\n   - 视觉：产品特写+氛围场景\n   - CTA：引导向下滚动元素\n\n2. 痛点挖掘区（3屏）\n   - 版式：左文右图/上文下图\n   - 视觉：场景化插图，引发共鸣\n   - 色调：偏冷色调制造焦虑感\n\n3. 解决方案区（3-4屏）\n   - 产品展示：360度旋转/细节微距/使用场景\n   - 视觉：暖色调，营造希望感\n   - 动效：悬浮展示/参数高亮\n\n4. 信任背书区\n   - 认证图标、检测报告可视化\n   - 用户评价截图设计\n   - 媒体推荐Logo墙\n\n5. 紧迫感营造\n   - 限时活动倒计时视觉\n   - 销量数据可视化\n   - 库存紧张提示\n\n输出：\n- 每屏的详细视觉描述\n- 配色方案（主色/辅助色/点缀色）\n- 字体层级规划', ARRAY['电商', '详情页', '视觉策划', '排版']),

('跨境电商多语言主图', 'design', '生成适合Amazon/eBay等平台的英文主图', '作为跨境电商视觉专家，请设计Amazon/eBay合规的产品主图：\n\n产品：[产品名称]\n平台：[Amazon/eBay/独立站]\n目标市场：[美国/欧洲/日本/东南亚]\n\nAmazon主图规范（必遵）：\n1. 纯白色背景 (RGB 255,255,255)\n2. 产品占画面85%以上\n3. 无水印、文字、Logo（除产品本身）\n4. 无边框、阴影、修饰\n5. 格式：JPEG/JPG，宽高比1:1或58:45\n\n附图设计方案：\n1. 场景图：产品实际使用场景，展示尺寸比例\n2. 功能图：图标+简短英文标注核心功能\n3. 细节图：材质、工艺特写\n4. 对比图：与旧款/竞品的优势对比\n5. 尺寸图：标注准确尺寸（英制+公制）\n6. 包装图：展示内含物品清单\n7. 生活方式图：目标用户的使用场景\n\n文案要求：\n- 英文简洁有力，避免长句\n- 使用强动词：Save, Boost, Transform, Protect\n- 突出数字：50% Faster, 3X Durable\n- 符合当地文化习惯\n\n输出：\n- 7张图的详细设计方案\n- 每张图的英文文案建议\n- 配色方案（符合品类调性）', ARRAY['跨境电商', '亚马逊', '英文主图', '设计']),

('详情页连贯图片系列设计', 'design', '为一款产品生成10张连贯的详情页图片规划', '请作为电商详情页视觉策划，为单一产品设计10张连贯的销售图片系列：\n\n产品：[产品名称]\n核心卖点：[卖点1/卖点2/卖点3]\n目标人群：[用户画像]\n价格带：[高端/中端/平价]\n\n系列图片规划（10张连贯视觉）：\n\n【第1张】主图 - 首屏抓眼球\n- 类型：产品特写+场景融合\n- 构图：产品占比70%，背景虚化场景\n- 文案位置：顶部或底部留白区域\n- 色调：品牌主色+高对比度\n- 目的：3秒内传达产品是什么+核心价值\n\n【第2张】痛点共鸣 - 引发需求\n- 类型：场景化插画/摄影\n- 视觉：使用前的问题场景（偏冷色调）\n- 人物表情：困扰/不便/失望\n- 文字："你是否也遇到...？[具体问题]"\n- 目的：让用户产生"这就是我"的共鸣\n\n【第3张】解决方案亮相 - 产品登场\n- 类型：产品正面完整展示\n- 角度：45度斜角，展示立体感\n- 光效：戏剧光/柔光，突出质感\n- 背景：纯色或渐变色\n- 文字：产品名称+一句话核心卖点\n- 目的：建立"这就是答案"的印象\n\n【第4张】核心功能拆解 - 局部特写\n- 类型：细节微距摄影\n- 焦点：产品最关键部件/材质细节\n- 辅助：标注线指向+图标说明\n- 对比：放大展示与普通产品的区别\n- 目的：用细节证明品质\n\n【第5张】使用场景 - 生活方式\n- 类型：场景化生活照\n- 环境：目标用户的典型使用场景\n- 人物：模特使用产品的自然状态\n- 氛围：温馨/专业/轻松（依产品定）\n- 光影：自然光，真实感\n- 目的：让用户想象自己使用的情景\n\n【第6张】尺寸/规格可视化\n- 类型：信息图设计\n- 元素：产品+参照物（手/手机/硬币）+尺寸标注\n- 角度：平视或俯视\n- 排版：清晰标注长/宽/高/重量\n- 目的：消除用户对大小的不确定感\n\n【第7张】多色/多款展示\n- 类型：阵列式展示\n- 布局：产品不同颜色/款式并排\n- 构图：对称或错落有致的排列\n- 光影：统一光源，保持一致性\n- 目的：展示选择范围，提高停留时长\n\n【第8张】对比优势图 - 竞品PK\n- 类型：左右分栏对比\n- 左侧：普通产品/旧方式（灰调处理）\n- 右侧：本产品（鲜艳高亮）\n- 对比维度：功能/材质/体验/价格\n- 目的：突出差异化优势\n\n【第9张】信任背书 - 认证/检测\n- 类型：证书+产品合成图\n- 元素：权威认证logo、检测报告、奖项\n- 排版：产品居大，认证图标环绕\n- 风格：专业、可信、正式\n- 目的：消除购买顾虑，建立信任\n\n【第10张】行动召唤 - 紧迫感营造\n- 类型：促销信息海报\n- 元素：限时优惠标签、价格对比、赠品展示\n- 色调：暖色调（红/橙/金）刺激行动\n- 排版：价格大字突出，原价划线\n- CTA按钮设计：立即购买/限时抢购\n- 目的：促成下单转化\n\n视觉连贯性要求：\n- 色调统一：所有图片使用同一套配色（主色+辅助色+中性色）\n- 光影一致：光源方向保持统一（建议左上方45度）\n- 风格协调：全部实拍或全部插画，不混搭\n- 品牌元素：每张图都出现品牌Logo或标志性视觉元素\n- 字体统一：标题字体、正文字体保持一致\n\n输出格式：\n- 每张图的详细视觉描述（200字+）\n- Midjourney提示词（每张图独立提示词）\n- 整体配色方案代码\n- 字体搭配建议', ARRAY['电商', '详情页', '图片系列', '连贯设计']),

('一产品多海报变体生成', 'design', '基于同一产品生成8种不同风格营销海报', '请作为电商营销设计师，基于同一产品创作8种不同风格的营销海报：\n\n产品信息：\n- 产品：[产品名称]\n- 品类：[填写类别]\n- 核心卖点：[最关键的一个卖点]\n- 目标人群：[年龄/性别/职业/兴趣]\n\n保持不变的元素（确保一致性）：\n- 产品主体：同角度/同光线/同材质表现\n- 产品比例：占画面30-50%（依风格微调）\n- 品牌Logo：固定位置（建议右下角）\n- 核心文案：同一句slogan，字体一致\n\n8种海报风格变体：\n\n【风格1】极简主义风\n- 背景：纯白色或浅灰色，无多余元素\n- 产品：居中摆放，轻微投影增加立体感\n- 字体：无衬线细体字（如Helvetica Light）\n- 配色：黑白灰+产品本色\n- 适用：高端数码、设计师品牌、极简生活用品\n- 氛围：干净、高级、克制\n\n【风格2】生活方式风\n- 背景：真实的居家/办公场景，虚化景深\n- 产品：自然摆放，与场景物品互动\n- 人物：手部入镜或背影，不露脸\n- 色调：暖色调，模拟自然光（色温3000-4000K）\n- 适用：家居用品、厨房电器、办公用品\n- 氛围：温馨、真实、可代入\n\n【风格3】科技感/未来风\n- 背景：深色渐变（深蓝/黑/紫）+ 光效线条\n- 产品：添加发光边缘/全息投影效果\n- 元素：几何图形、数据流、网格线\n- 字体：科技感无衬线（如Eurostile）\n- 色调：冷色调为主+霓虹色点缀\n- 适用：电子产品、智能设备、科技配件\n- 氛围：前沿、智能、高端\n\n【风格4】复古/怀旧风\n- 背景：复古纹理（牛皮纸/老报纸/木纹）\n- 滤镜：添加颗粒感、暗角、轻微褪色\n- 字体：复古衬线体或手写体\n- 色调：暖黄、 sepia色调（棕褐色调）\n- 元素：复古图标、邮戳、手写标签\n- 适用：手工艺品、复古服饰、食品\n- 氛围：怀旧、手工、有温度\n\n【风格5】活力运动风\n- 背景：动态模糊或爆炸式色块\n- 产品：倾斜角度，营造动感\n- 元素：速度线、几何碎片、能量波纹\n- 色调：高饱和度（橙、红、蓝）\n- 字体：粗体斜体，有力量感\n- 适用：运动装备、能量饮料、健身产品\n- 氛围：动感、活力、激情\n\n【风格6】奢华高端风\n- 背景：深色绒布/大理石/金属质感\n- 光影：戏剧性侧光，强烈明暗对比\n- 元素：金色装饰线、水晶、镜面反射\n- 色调：黑金配色、深红+金\n- 字体：优雅衬线体（如Didot/Bodoni）\n- 适用：珠宝、奢侈品、高端美妆\n- 氛围：尊贵、稀有、仪式感\n\n【风格7】可爱/萌系风\n- 背景：马卡龙色系渐变或可爱图案\n- 元素：手绘插画、卡通贴纸、星星爱心\n- 字体：圆润手写体或卡通字体\n- 色调：粉色、薄荷绿、淡黄等糖果色\n- 表情：如产品可加拟人表情\n- 适用：文创产品、零食、女性用品\n- 氛围：可爱、治愈、轻松\n\n【风格8】环保自然风\n- 背景：植物、木纹、石材等自然纹理\n- 元素：绿叶、干花、麻绳、再生纸标签\n- 色调：大地色系（绿、棕、米白）\n- 字体：手写体或有机形态字体\n- 认证：环保标志、有机认证图标\n- 适用：有机食品、天然护肤品、可持续产品\n- 氛围：自然、健康、负责任\n\n技术规格（所有海报统一）：\n- 尺寸：1080×1920px（9:16竖版）\n- 分辨率：300dpi\n- 格式：PSD源文件 + JPG导出\n- 出血：四周预留30px安全区\n- 字体：所有字体需可商用或已授权\n\n输出要求：\n- 8种风格的详细视觉描述（各150字+）\n- 每种风格的Midjourney完整提示词\n- 配色方案代码（每种风格）\n- 字体搭配建议\n- 适用场景和人群分析', ARRAY['电商', '海报设计', '多风格', '变体生成']),

('主图AB测试变体设计', 'design', '为同一产品生成6个不同主图用于AB测试', '请作为电商转化优化专家，为同一产品创建6个主图变体进行AB测试：\n\n测试目标：提升主图点击率/转化率\n产品：[产品名称]\n当前基准主图：[描述现有主图特点]\n\n6个测试变体设计：\n\n【变体A】场景化场景版\n- 背景：真实使用场景（非纯色）\n- 产品：自然融入场景，非孤立展示\n- 优势：提升代入感，生活方式营销\n- 测试假设：场景化比白底图更吸引点击\n\n【变体B】纯产品放大版\n- 背景：纯白/纯黑极简背景\n- 产品：占据画面85%以上，细节清晰\n- 光线：专业棚拍，无阴影\n- 优势：符合Amazon规范，突出产品本身\n- 测试假设：大产品图展现更多细节，提升信任\n\n【变体C】卖点标注版\n- 基础：产品正面清晰图\n- 叠加：箭头+图标标注核心卖点（3-5个）\n- 文字：简短英文卖点（如"50% Faster"）\n- 优势：信息密度高，快速传递价值\n- 测试假设：标注卖点减少决策时间\n\n【变体D】社交证明版\n- 基础：产品图（占画面60%）\n- 叠加：星级评分、销量数字、好评截图\n- 元素："10,000+ Sold" / "★★★★★" 徽章\n- 优势：利用从众心理，降低决策风险\n- 测试假设：社交证明比纯产品图更促转化\n\n【变体E】对比展示版\n- 布局：左右分屏或上下排列\n- 内容：使用前vs使用后 / 旧款vs新款\n- 视觉：对比效果明显，差异可视化\n- 优势：直观展示价值，消除疑虑\n- 测试假设：对比图比单图更能说明价值\n\n【变体F】限时促销版\n- 基础：产品清晰展示\n- 叠加：促销标签、折扣数字、倒计时元素\n- 色彩：红色/橙色等紧迫感色彩\n- 文字："Limited Time -30%" / "Flash Sale"\n- 优势：制造紧迫感，促进行动\n- 测试假设：促销信息在主图直接展示提升转化\n\n测试设计规范：\n- 控制变量：除测试元素外，其他保持一致\n- 产品角度：所有变体使用相同产品角度\n- 光线条件：相同光源方向，确保可比性\n- 品牌Logo：固定位置，大小一致\n- 文件规格：相同尺寸、格式、压缩率\n\n测试执行方案：\n1. 分流：各变体随机分配20%流量（对照组20%）\n2. 周期：至少运行7天（覆盖工作日和周末）\n3. 样本量：每组至少1000次曝光\n4. 指标：点击率、转化率、加购率\n\n数据分析维度：\n- 整体表现：哪个变体CTR最高\n- 人群细分：新客/老客偏好差异\n- 设备差异：移动端vs PC端表现\n- 时段分析：不同时段效果差异\n\n结果应用：\n- 冠军版本：全量使用表现最佳变体\n- 亚军版本：作为对照组持续测试新方案\n- 迭代优化：基于获胜元素设计新变体\n\n输出：\n- 6个变体的详细设计描述\n- Midjourney/SD提示词（控制变量说明）\n- 测试执行检查清单\n- 数据分析模板', ARRAY['电商', '主图', 'AB测试', '转化率优化']),

('3C数码产品渲染图', 'design', '生成专业3C产品渲染图（手机/耳机/充电宝等）', '请作为3C产品渲染专家，生成专业级数码产品渲染图方案：\n\n产品类型：[手机/耳机/充电宝/充电器/数据线/智能手表]\n产品材质：[金属/塑料/玻璃/硅胶/织物]\n目标平台：[京东/天猫/Amazon/独立站]\n\n渲染风格选择：\n\n【风格1】悬浮科技风（适合首页主图）\n- 构图：产品45度悬浮，轻微倾斜增加动感\n- 背景：深灰渐变（#1a1a2e到#16213e）\n- 光源：三点布光（主光45度、补光、轮廓光）\n- 反射：添加柔和地面反射，增强立体感\n- 粒子：周围添加微小光点/数据粒子\n- 氛围：未来感、科技、专业\n\n【风格2】极简白底风（适合详情页标准图）\n- 背景：纯白（RGB 255,255,255）\n- 产品：正视图或45度角，无阴影或微阴影\n- 光线：柔光箱照明，无反光过曝\n- 后期：轻微对比度提升，边缘锐利\n- 标准：符合Amazon/京东白底图规范\n- 目的：清晰展示产品外观\n\n【风格3】场景融合风（适合生活方式营销）\n- 环境：办公桌/床头柜/咖啡厅桌面\n- 景深：产品清晰，背景适度虚化\n- 搭配：与产品相关的配件自然摆放\n- 光线：暖色调自然光（模拟窗户光）\n- 角度：略高于平视，展示桌面场景\n- 氛围：真实使用场景，提升代入感\n\n【风格4】爆炸分解图（适合展示内部工艺）\n- 布局：产品各部件沿中心线分散排列\n- 展示：外壳、电路板、电池、接口等分层\n- 标注：关键部件名称和技术参数\n- 风格：技术图解风，半透明材质表现\n- 光线：均匀照明，突出内部结构\n- 目的：展示产品做工和用料\n\n【风格5】动态使用图（适合功能展示）\n- 构图：产品+动态效果叠加\n- 效果：充电发光、屏幕亮起、声波扩散\n- 人物：手部入镜操作产品（不露脸）\n- 界面：屏幕显示真实UI界面\n- 光线：屏幕光+环境光混合\n- 目的：直观展示产品使用状态\n\n材质表现要点：\n\n金属材质（铝合金/不锈钢）：\n- 反射：柔和的环境反射\n- 高光：清晰的高光线条\n- 纹理：细腻的拉丝或喷砂质感\n- 倒角：边缘倒角的高光表现\n\n塑料材质：\n- 光泽：区分哑光/亮面/磨砂\n- 色彩：准确还原产品色（考虑菲涅尔效应）\n- 合模线：适当表现增加真实感\n\n玻璃材质（屏幕/镜头）：\n- 反射：环境映射+黑色渐变反射\n- 折射：透过玻璃看到内部结构\n- 高光：细长的高光线条\n\n织物/硅胶：\n- 纹理：细腻的编织纹理或磨砂感\n- 柔软：边缘轻微圆角表现柔软度\n- 吸光：较少高光，漫反射为主\n\n渲染技术规格：\n- 软件：C4D + Octane/Redshift / KeyShot\n- 分辨率：3000×3000px起步（支持裁切）\n- 格式：PNG透明底 + JPG高质量\n- 色彩空间：sRGB\n- 位深：8bit（电商）或16bit（印刷）\n\n后期处理流程：\n1. 基础调整：曝光、对比度、白平衡\n2. 瑕疵修复：去除灰尘、划痕\n3. 锐化：智能锐化，增强边缘\n4. 调色：统一色调，提升饱和度\n5. 输出：Web用72dpi，印刷用300dpi\n\n输出要求：\n- 5种风格的详细渲染参数设置\n- C4D/KeyShot场景文件结构说明\n- 灯光布置图解\n- 材质参数数值表\n- 后期PSD图层说明', ARRAY['电商', '3C数码', '产品渲染', 'C4D']),

('食品美食摄影方案', 'design', '电商食品类产品拍摄和后期方案', '请作为美食摄影师，为电商食品类产品制定拍摄方案：\n\n食品类型：[零食/饮料/烘焙/生鲜/调味品/保健品]\n包装形式：[袋装/瓶装/盒装/散装]\n风格定位：[高端/亲民/健康/ indulgence]\n\n拍摄场景规划：\n\n【场景1】食材本真风（适合原料展示）\n- 背景：天然材质（木板/大理石/麻布）\n- 摆放：产品+原材料自然摆放\n- 示例：蜂蜜+蜂巢+木勺，坚果+果壳散落\n- 光线：侧逆光，突出质感和纹理\n- 色调：暖色调，饱和度适中\n- 景深：中等景深，前后景适度虚化\n\n【场景2】俯拍平铺风（适合包装展示）\n- 角度：垂直90度俯拍\n- 布局：产品居中，配料环绕摆放\n- 道具：餐具、配料、装饰叶\n- 背景：纯色或纹理背景（与包装对比）\n- 光线：柔和顶光或柔光箱\n- 后期：轻微调色，统一色调\n\n【场景3】食用场景风（适合诱导购买）\n- 场景：真实食用场景（餐桌/沙发/户外）\n- 人物：手部动作（拿/倒/撕/咬）\n- 氛围：愉快、享受、分享\n- 光线：自然光，温暖感\n- 焦点：食物清晰，背景虚化\n- 动态：捕捉食物被咬/倒出的瞬间\n\n【场景4】创意微距风（适合细节展示）\n- 焦点：食品细节特写（纹理/层次/夹心）\n- 角度：非常规角度（切面/掰开/咬痕）\n- 光线：侧光突出质感\n- 背景：纯色或极度虚化\n- 目的：展示产品质感和用料\n\n【场景5】礼盒/组合装（适合节庆营销）\n- 构图：礼盒打开状态，产品整齐排列\n- 装饰：丝带、贺卡、装饰花\n- 场景：节庆氛围（春节/中秋/圣诞）\n- 光线：温暖明亮\n- 角度：45度展示内部\n- 目的：作为礼品的心动感\n\n光线设置方案：\n\n自然光方案（预算有限）：\n- 时间：上午10点或下午3-4点\n- 位置：靠窗，使用窗帘柔化\n- 反光板：白色泡沫板补光\n- 遮光：黑卡纸控制光线方向\n\n人工光方案（专业级）：\n- 主灯：柔光箱45度侧光\n- 补光：对面白色反光板\n- 轮廓光：后方或侧后方勾勒边缘\n- 背景光：独立照亮背景（分离主体）\n\n色彩管理：\n- 白平衡：拍摄前校正\n- 色温：食品通常用5500-6000K（中性偏暖）\n- 饱和度：食品可增加10-15%饱和度\n- 色相：保持食品自然色彩，不过度调色\n\n特殊食品处理技巧：\n\n饮料类：\n- 冰块：使用假冰或快速拍摄\n- 气泡：使用苏打水制造，或用甘油+泡腾片\n- 冷凝：喷水雾制造清凉感\n- 透光：背光拍摄展示液体通透感\n\n烘焙类：\n- 新鲜度：拍摄前烘烤，保持蓬松\n- 黄油光泽：刷蛋黄液或植物油\n- 撒粉：糖粉/面粉的艺术性撒落\n- 切面：展示内部组织气孔\n\n肉类/生鲜：\n- 光泽：刷油或喷水保持新鲜感\n- 颜色：避免过度加热导致变色\n- 摆盘：生熟分开，注意食品安全\n- 冰块：保持生鲜产品低温感\n\n包装食品：\n- 反光处理：使用偏振镜消除包装反光\n- 形状：保持包装饱满，可内衬填充\n- 标签：确保正面标签完整清晰\n- 组合：不同口味/规格组合展示\n\n后期处理要点：\n1. 基础校正：曝光、白平衡、透视校正\n2. 瑕疵修复：去除包装反光、灰尘\n3. 质感增强：适当锐化，突出纹理\n4. 色彩调整：HSL调整，突出食品色彩\n5. 背景处理：适当虚化或更换\n6. 最终输出：电商用72dpi，印刷用300dpi\n\n输出：\n- 各场景详细拍摄参数（相机/镜头/灯光）\n- 道具采购清单\n- 拍摄分镜脚本\n- 后期修图步骤说明\n- 示例成片参考描述', ARRAY['电商', '食品', '美食摄影', '产品拍摄']),

-- 网页制作类
('响应式Landing Page设计', 'design', '高转化率落地页完整设计方案', '请作为高级UI/UX设计师，为[SaaS/电商/服务类产品]设计响应式Landing Page：\n\n设计目标：\n- 核心转化目标：[注册/购买/预约/下载]\n- 目标转化率基准：[行业基准+%]\n- 主要流量来源：[搜索引擎/社交媒体/广告]\n\n页面结构（单页长滚动）：\n\n1. Hero Section（首屏）\n   - 价值主张：主标题（10字内）+ 副标题（20字内）\n   - 视觉焦点：产品界面mockup/3D插图/视频背景\n   - CTA按钮：[主按钮文案] + [次按钮文案]\n   - 信任元素：知名客户Logo/用户数量/评分\n\n2. 痛点共鸣区\n   - 标题：你是否也遇到...[具体问题]？\n   - 3个痛点卡片：图标+问题描述+情绪共鸣\n   - 视觉：暗色调，制造紧迫感\n\n3. 解决方案展示\n   - 产品核心功能展示（3-4个）\n   - 每个功能：标题+简短描述+界面截图/GIF\n   - 交互：悬停效果、点击展开\n\n4. 社会证明区\n   - 客户评价轮播：头像+姓名+职位+评价+星级\n   - 数据证明：使用数据可视化（节省XX小时/提升XX%）\n   - 案例研究：知名客户成功故事\n\n5. 定价策略区\n   - 3档定价对比（推荐中间档高亮）\n   - 年费优惠突出显示\n   - FAQ手风琴折叠\n\n6. 最终CTA区\n   - 紧迫感：限时优惠倒计时\n   - 降低风险：免费试用/退款保证\n   - 最后转化按钮\n\n设计规范：\n- 配色：主色[色值]、辅助色[色值]、背景色[色值]\n- 字体：标题[字体]、正文[字体]、代码[字体]\n- 间距：8px网格系统\n- 动效：滚动触发动画、微交互\n\n响应式断点：\n- Desktop: 1440px+\n- Tablet: 768px-1439px\n- Mobile: <768px\n\n输出：\n- Figma设计稿结构描述\n- 各section详细规格\n- 交互动画说明', ARRAY['网页设计', '落地页', '响应式', '转化']),

('现代企业官网设计系统', 'design', '完整的企业官网设计规范和组件', '请作为设计系统架构师，为[科技公司/传统企业/创业公司]构建官网设计系统：\n\n品牌调性：\n- 行业：[金融科技/医疗健康/教育培训/制造业]\n- 调性：[专业严谨/创新活力/温暖亲和/高端奢华]\n- 竞品：[列出3个参考网站]\n\nDesign Token规范：\n\n1. 色彩系统\n   - 主色：Primary-500 = [色值]，用于CTA、重点\n   - 辅助色：Secondary-500 = [色值]，用于点缀\n   - 语义色：Success [色值] / Warning [色值] / Error [色值] / Info [色值]\n   - 中性色：Black [色值] / Gray-100到900 / White [色值]\n   - 背景：Bg-Primary [色值] / Bg-Secondary [色值]\n\n2. 字体系统\n   - 字体族：Display [字体] / Body [字体] / Mono [字体]\n   - 字号比例：Hero(48px)/H1(36px)/H2(28px)/H3(22px)/Body(16px)/Small(14px)\n   - 行高：标题1.2 / 正文1.6 / 紧凑1.4\n   - 字重：Regular(400)/Medium(500)/Semibold(600)/Bold(700)\n\n3. 间距系统\n   - 基础单位：4px\n   - 间距尺度：4/8/12/16/24/32/48/64/96px\n   - 页面边距：Desktop 64px / Tablet 32px / Mobile 16px\n   - 组件间距：紧凑8px / 默认16px / 宽松32px\n\n4. 圆角与阴影\n   - 圆角：None(0)/Small(4px)/Medium(8px)/Large(16px)/Full(9999px)\n   - 阴影：Level1[小阴影]/Level2[卡片]/Level3[弹窗]/Level4[置顶]\n\n核心页面模板：\n\n1. 首页模板\n   - 全屏Hero + 价值主张\n   - Logo墙（客户/合作伙伴）\n   - 3大核心服务/产品卡片\n   - 数据展示（成就数字）\n   - 客户评价\n   - 最新动态/博客\n   - CTA区块\n\n2. 产品/服务页\n   - 产品介绍Hero\n   - 功能特性网格\n   - 使用流程步骤\n   - 定价方案\n   - FAQ\n\n3. 关于我们页\n   - 公司使命愿景\n   - 时间线里程碑\n   - 团队展示\n   - 办公环境/文化\n\n4. 联系我们页\n   - 联系信息卡片\n   - 地图嵌入\n   - 表单设计\n   - 社交媒体链接\n\n组件库清单：\n- Button: Primary/Secondary/Ghost/Icon variants\n- Card: 基础卡片/产品卡片/评价卡片/博文卡片\n- Form: Input/Select/Checkbox/Radio/Textarea\n- Navigation: 顶部导航/面包屑/分页/步骤条\n- Feedback: Toast/Modal/Alert/Loading\n- Data Display: Table/Accordion/Tabs/Badge\n\n输出：\n- 完整Design Token文档\n- 各页面线框图描述\n- 组件规格说明', ARRAY['网页设计', '企业官网', '设计系统', 'UI组件']),

-- 数据分析类
('销售数据深度分析', 'analysis', '电商销售数据的多维度分析框架', '请作为数据分析师，为电商业务制定销售数据分析方案：\n\n业务背景：\n- 平台类型：[综合电商/垂直品类/跨境电商]\n- 分析周期：[日/周/月/季度/年度]\n- 数据源：订单系统、用户行为、营销投放\n\n分析维度框架：\n\n1. 核心指标概览\n   - GMV（成交总额）= 订单数 × 客单价\n   - 转化率 = 下单人数/访客人数\n   - ARPU（用户平均收入）= 总收入/活跃用户数\n   - 复购率 = 复购用户数/总购买用户数\n   - 退款率 = 退款订单数/总订单数\n\n2. 时间维度分析\n   - 趋势分析：同比、环比、移动平均\n   - 周期性：周内分布（周末vs工作日）\n   - 季节性：节假日、大促期间表现\n   - 异常检测：识别异常波动及原因\n\n3. 商品维度分析\n   - 品类结构：各品类销售占比\n   - 商品排名：Top 20畅销/滞销商品\n   - 价格带分析：销量 vs 价格区间分布\n   - 新品表现：上架首月销售追踪\n   - 库存周转：周转率、滞销预警\n\n4. 用户维度分析\n   - 新老客结构：新客占比、老客贡献\n   - RFM模型：最近一次消费、消费频率、金额\n   - 用户分层：高价值/潜力/流失风险\n   - 地域分布：城市级别销售热力图\n   - 设备分析：PC/移动端转化率对比\n\n5. 营销效果分析\n   - 渠道ROI：各流量渠道投入产出\n   - 促销分析：满减/折扣对销量影响\n   - 广告转化：点击率、转化成本\n   - 优惠券使用率、客单价提升效果\n\n6. 竞争分析\n   - 市场份额变化趋势\n   - 竞品价格监控\n   - 品类渗透率对比\n\n分析方法工具：\n- SQL查询模板（提供常用查询语句）\n- Python分析脚本（Pandas数据清洗）\n- 可视化方案（Tableau/PowerBI仪表板）\n- 统计检验（AB测试结果显著性）\n\n输出交付：\n- 每日自动日报（关键指标摘要）\n- 每周深度分析报告（趋势+洞察+建议）\n- 交互式仪表板（支持下钻分析）\n- 异常预警机制（自动邮件通知）', ARRAY['数据分析', '电商', '销售', 'SQL']),

('用户行为路径分析', 'analysis', '网站/APP用户漏斗和路径优化', '请作为用户增长分析师，设计用户行为分析方案：\n\n产品类型：[电商/内容/工具/SaaS]\n分析目标：[提升注册/促进首单/提高留存/增加分享]\n\n核心漏斗分析：\n\n1. 获取-激活漏斗\n   曝光 → 点击 → 访问 → 注册 → 激活\n   - 各步骤转化率\n   - 流失节点识别\n   - 渠道质量对比（自然搜索/社交/广告）\n\n2. 电商转化漏斗\n   浏览 → 加购 → 结算 → 支付 → 复购\n   - 购物车放弃率分析\n   - 结算页流失原因\n   - 支付成功率优化\n\n3. 内容消费漏斗\n   曝光 → 点击 → 阅读 → 互动 → 关注 → 分享\n   - 完读率分析\n   - 内容偏好聚类\n   - 推荐算法效果\n\n行为路径分析：\n\n1. 用户旅程地图\n   - 新用户首次使用路径\n   - 典型用户日常使用模式\n   - 高价值用户行为特征\n   - 流失用户前兆行为\n\n2. 页面流转分析\n   - 入口页面分布\n   - 退出页面分析\n   - 页面停留时长\n   - 点击热图分析\n\n3. 功能使用分析\n   - 功能渗透率（使用用户数/总用户数）\n   - 功能使用频次\n   - 功能关联性分析（A功能→B功能）\n\n关键指标监控：\n\n1. 参与度指标\n   - DAU/MAU（日/月活跃用户）\n   - 使用时长\n   - 使用频次\n   - 功能使用深度\n\n2. 留存指标\n   - 次日留存、7日留存、30日留存\n   -  cohort分析（同期群分析）\n   - 流失预警模型\n\n3. 转化指标\n   - 各目标转化率\n   - 转化周期（从注册到首单天数）\n   - ARPPU（付费用户平均收入）\n\n分析工具建议：\n- 埋点方案：事件设计规范\n- 分析平台：Mixpanel/Amplitude/神策数据\n- 可视化：用户流程桑基图、热力图\n- SQL查询：漏斗分析SQL模板\n\n优化建议输出：\n- 最高优先级优化点（数据支撑）\n- AB测试方案设计\n- 预期效果测算', ARRAY['用户分析', '漏斗', '行为路径', '转化']),

('数据可视化仪表板设计', 'analysis', '业务监控仪表板的布局和指标设计', '请作为BI设计师，为[业务部门]设计数据监控仪表板：\n\n业务场景：[销售/运营/产品/管理层驾驶舱]\n更新频率：实时/小时/日/周\n用户角色：执行层/管理层/决策层\n\n仪表板结构设计：\n\n1. 顶部概览区（KPI卡片区）\n   布局：4-6个核心指标卡片横向排列\n   \n   指标设计：\n   - 主指标：大数字显示，同比变化箭头\n   - 副指标：趋势迷你图(Sparkline)\n   - 目标完成度：环形进度条\n   \n   示例指标：\n   - 今日GMV ¥123,456 ↑12%\n   - 活跃用户 12,345 ↑5%\n   - 订单数 1,234 ↓2%\n   - 转化率 3.45% ↑0.3pp\n\n2. 趋势分析区（左半区）\n   - 主趋势图：折线图，时间维度筛选（7天/30天/90天）\n   - 对比功能：支持去年同期对比\n   - 下钻交互：点击可查看明细\n\n3. 结构分析区（右半区）\n   - 饼图/环形图：品类/渠道占比\n   - 条形图：Top 10排名\n   - 切换标签：不同维度切换\n\n4. 明细数据区（底部）\n   - 表格展示关键明细\n   - 排序、筛选、分页\n   - 导出CSV功能\n\n5. 异常预警区（侧边/弹窗）\n   - 红色预警卡片：超出阈值指标\n   - 智能洞察：自动发现的数据异常\n   - 建议行动：基于数据的优化建议\n\n视觉设计规范：\n\n1. 色彩系统\n   - 主色调：品牌色用于重点数据\n   - 功能色：绿(正常)/红(异常)/黄(警告)/蓝(信息)\n   - 背景：浅灰(#F5F5F5)卡片白色\n   - 文字：深灰标题、中灰正文\n\n2. 字体层级\n   - KPI数字：32px Bold\n   - 指标名称：14px Regular\n   - 变化幅度：12px Medium\n   - 坐标轴：11px\n\n3. 图表规范\n   - 折线图：主线条2px，数据点4px\n   - 柱状图：圆角4px，间距适中\n   - 饼图：环形内半径40%，标签外置\n   - 统一图例位置和样式\n\n4. 响应式布局\n   - Desktop：1920×1080，4列网格\n   - Tablet：768px，2列网格\n   - Mobile：垂直堆叠\n\n交互设计：\n- 全局筛选器：日期范围、业务线\n- 图表联动：点击饼图筛选其他图表\n- 钻取导航：面包屑路径显示\n- 刷新按钮：手动刷新+自动刷新开关\n\n工具实现建议：\n- 轻量级：Metabase/Redash\n- 企业级：Tableau/PowerBI/Looker\n- 自研：React + ECharts/AntV\n\n输出：\n- 各区块详细布局描述\n- 配色方案代码\n- 交互流程说明', ARRAY['数据可视化', '仪表板', 'BI', '监控']),

('SQL数据分析查询模板', 'analysis', '常用业务分析场景的SQL查询', '请作为数据工程师，提供以下业务场景的SQL查询模板：\n\n数据库：MySQL/PostgreSQL\n表结构假设：\n- users(用户表): user_id, register_date, channel\n- orders(订单表): order_id, user_id, order_date, amount, status\n- products(产品表): product_id, category, price\n- order_items(订单明细): item_id, order_id, product_id, quantity\n\n1. 用户留存分析（Cohort Analysis）\n\n查询目标：计算每日注册用户的次日/7日/30日留存率\n\nSQL逻辑：\n- 确定每个用户的注册日期\n- 计算注册后第N天是否活跃\n- 按注册日期分组计算留存率\n\n预期输出格式：\n注册日期 | 当日注册人数 | 次日留存 | 7日留存 | 30日留存\n2024-01-01 | 1000 | 45% | 25% | 12%\n\n2. RFM用户分层\n\n查询目标：按最近消费(R)、消费频率(F)、金额(M)给用户打分\n\n维度定义：\n- R: 距离今天的天数（1-5分）\n- F: 过去一年订单数（1-5分）\n- M: 过去一年总金额（1-5分）\n\n分层结果：\n- 重要价值客户：R高 F高 M高\n- 重要发展客户：R高 F低 M高\n- 重要保持客户：R低 F高 M高\n- 一般客户：其他组合\n\n3. 商品关联分析（购物篮分析）\n\n查询目标：找出经常一起购买的商品组合\n\n分析方法：\n- 计算支持度：A和B同时购买的订单占比\n- 计算置信度：买A的用户中买B的比例\n- 计算提升度：置信度/B的单独购买率\n\n应用：\n- 商品推荐\n- 捆绑销售\n- 陈列优化\n\n4. 销售趋势同比环比\n\n查询目标：计算每月销售额及同比、环比\n\nSQL要点：\n- 按月聚合销售额\n- 自连接获取上月、去年同期数据\n- 计算增长率\n\n5. 漏斗分析（用户转化路径）\n\n查询目标：分析从浏览到购买的转化漏斗\n\n步骤定义：\n- 浏览商品页\n- 加入购物车\n- 进入结算页\n- 提交订单\n- 完成支付\n\n计算：\n- 每步用户数\n- 每步转化率\n- 总体转化率\n- 流失节点识别\n\n6. 库存周转分析\n\n查询目标：计算商品库存周转天数\n\n公式：\n周转天数 = 平均库存 / 日均销量\n\n分级：\n- 畅销：周转<7天\n- 正常：7-30天\n- 滞销：>30天\n- 超期：>90天（需清仓）\n\n7. 异常检测查询\n\n目标：识别异常订单、刷单嫌疑\n\n检测规则：\n- 同一地址多账号下单\n- 深夜集中下单\n- 大额订单占比突增\n- 退货率异常用户\n\n8. 用户LTV预测\n\n目标：基于早期行为预测用户终身价值\n\n特征：\n- 首单金额\n- 首单品类\n- 注册渠道\n- 前7天活跃度\n\n输出：\n- 每个SQL查询的完整代码\n- 索引优化建议\n- 查询性能优化技巧', ARRAY['SQL', '数据分析', '查询模板', '数据库']),

('AB测试结果分析', 'analysis', '科学的AB实验设计和结果评估', '请作为数据科学家，设计并分析以下A/B测试：\n\n实验背景：\n- 测试目标：[提升点击率/增加转化率/提高留存]\n- 实验页面：[首页/详情页/结算页/邮件模板]\n- 变体说明：\n  - 对照组(A)：当前版本\n  - 实验组(B)：新方案[具体描述]\n\n1. 实验设计阶段\n\n样本量计算：\n- 基准转化率：[当前值，如3%]\n- 最小可检测提升(MDE)：[如0.5%绝对提升]\n- 显著性水平(α)：[通常0.05]\n- 统计功效(1-β)：[通常0.8]\n- 计算所需样本量：每组[X]用户\n- 预计实验时长：[X]天\n\n分流策略：\n- 随机算法：用户ID哈希取模\n- 分层维度：[新/老用户，设备类型，地域]\n- 正交实验：多实验互不影响\n- 流量分配：[A:50%, B:50%]或[A:90%, B:10%灰度]\n\n2. 数据收集监控\n\n核心指标：\n- 北极星指标：[如转化率]\n- 护栏指标：[如加载时长，不能变差]\n- 辅助指标：[点击率、停留时长、跳出率]\n\n数据质量检查：\n- 样本比例是否符合设定\n- 两组用户特征是否均衡\n- 数据缺失/异常值处理\n- 季节性和外部事件影响\n\n3. 统计分析\n\n假设检验：\n- H0: B组转化率 = A组转化率\n- H1: B组转化率 ≠ A组转化率\n- 检验方法：双样本Z检验/卡方检验\n- 显著性：p-value < 0.05拒绝H0\n\n置信区间：\n- B组转化率估计：[点估计] ± [边际误差]\n- 两组差异估计：Δ = [差值], 95% CI: [下限, 上限]\n\n统计功效分析：\n- 实际观测到的提升：[相对提升%]\n- 实际p-value：[X]\n- 结论：[显著/不显著]\n\n4. 结果解读\n\n情景分析：\n\n情景1：效果显著且正向\n- B组显著优于A组(p<0.05)\n- 相对提升[X]%，绝对提升[X]%\n- 业务影响预估：每日增加[X]订单\n- 决策：全量发布\n\n情景2：效果正向但不显著\n- B组表现略好但p>0.05\n- 可能原因：样本不足/效果太小\n- 决策：延长实验或扩大流量\n\n情景3：效果显著但负向\n- B组显著差于A组\n- 分析：新方案有问题\n- 决策：停止实验，回滚A\n\n情景4：无显著差异\n- 两组表现相当\n- 决策：从其他维度选择（如开发成本）\n\n5. 分群分析\n\n细分维度：\n- 新用户 vs 老用户\n- 移动端 vs PC端\n- 不同地域\n- 不同流量渠道\n\n发现：\n- B组在[某细分]表现特别突出\n- 在[某细分]表现较差\n- 建议：针对[细分]定向发布\n\n6. 长期影响评估\n\n短期 vs 长期：\n- 新奇效应：新方案初期数据好\n- 学习效应：用户需要时间适应\n- 建议实验时长：至少2周/包含周末\n\n7. 实验文档模板\n\n实验报告应包含：\n- 实验背景和目标\n- 假设和指标定义\n- 实验设计和样本量\n- 数据质量和均衡性检验\n- 统计结果（p-value, 置信区间）\n- 业务影响评估\n- 决策和建议\n- 后续行动计划\n\n输出：\n- 实验设计检查清单\n- 分析SQL/Python代码模板\n- 结果汇报PPT结构', ARRAY['AB测试', '实验设计', '统计检验', '优化']);
